import os
from datetime import datetime, timedelta, timezone
from bytewax.dataflow import Dataflow
import bytewax.operators as op
from bytewax.testing import TestingSource, run_main
from bytewax.connectors.stdio import StdOutSink
from bytewax.operators import StatefulLogic

class SimpleLogic(StatefulLogic):
    def __init__(self, step_id):
        self.step_id = step_id
        self.items = []
        self.first_added_at = None

    def on_item(self, value):
        print(f"on_item called with value={value}")
        if not self.items:
            self.first_added_at = datetime.now(timezone.utc)
        self.items.append(value)
        return ([], StatefulLogic.RETAIN)

    def notify_at(self):
        if self.first_added_at:
            next_time = self.first_added_at + timedelta(seconds=2)
            print(f"notify_at returning {next_time}")
            return next_time
        return None

    def on_notify(self):
        print("on_notify called!")
        items = list(self.items)
        self.items = []
        self.first_added_at = None
        return ([("abandoned", items)], StatefulLogic.DISCARD)

    def on_eof(self):
        print("on_eof called!")
        if self.items:
            return ([("eof_abandoned", list(self.items))], StatefulLogic.DISCARD)
        return ([], StatefulLogic.DISCARD)

    def snapshot(self):
        return (self.items, self.first_added_at)

flow = Dataflow("test_flow")
stream = op.input("inp", flow, TestingSource([("user1", "item1"), ("user1", "item2")]))
res = op.stateful("stateful_step", stream, lambda s: SimpleLogic("stateful_step"))
op.output("out", res, StdOutSink())

if __name__ == "__main__":
    run_main(flow)

